import java.util.*;
public class FindAllAnagrams {
    public static List<Integer> findAnagrams(String s, String p) {
        List<Integer> result = new ArrayList<>();
        if (s.length() < p.length()) return result;
        int[] need = new int[26], have = new int[26];
        int k = p.length();
        for (char c : p.toCharArray()) need[c - 'a']++;
        // Build first window:
        for (int i = 0; i < k; i++) have[s.charAt(i) - 'a']++;
        if (Arrays.equals(need, have)) result.add(0);
        // Slide:
        for (int i = k; i < s.length(); i++) {
            have[s.charAt(i) - 'a']++;        // add right
            have[s.charAt(i - k) - 'a']--;   // remove left
            if (Arrays.equals(need, have)) result.add(i - k + 1);
        }
        return result;
    }
    public static void main(String[] args) {
        System.out.println(findAnagrams("cbaebabacd", "abc")); // [0, 6]
        System.out.println(findAnagrams("abab", "ab"));        // [0, 1, 2]
        System.out.println("O(n) — fixed window, O(1) space (int[26] comparison)");
    }
}

