import java.util.*;
public class SortByFrequency {
    public static String frequencySort(String s) {
        // Count frequencies:
        Map<Character, Integer> freq = new HashMap<>();
        for (char c : s.toCharArray()) freq.merge(c, 1, Integer::sum);
        // Bucket sort by frequency:
        @SuppressWarnings("unchecked")
        List<Character>[] buckets = new List[s.length() + 1];
        for (var entry : freq.entrySet()) {
            int f = entry.getValue();
            if (buckets[f] == null) buckets[f] = new ArrayList<>();
            buckets[f].add(entry.getKey());
        }
        // Build result from highest frequency:
        StringBuilder sb = new StringBuilder();
        for (int f = s.length(); f >= 1; f--) {
            if (buckets[f] != null) {
                for (char c : buckets[f]) {
                    for (int i = 0; i < f; i++) sb.append(c);
                }
            }
        }
        return sb.toString();
    }
    public static void main(String[] args) {
        System.out.println(frequencySort("tree"));   // eert or eetr
        System.out.println(frequencySort("cccaaa")); // aaaccc or cccaaa
        System.out.println(frequencySort("Aabb"));   // bbAa or bbaA
        System.out.println("O(n) bucket sort — frequency as bucket index");
    }
}

