public class MinStepsAnagram {
    public static int minSteps(String s, String t) {
        int[] freq = new int[26];
        for (char c : s.toCharArray()) freq[c - 'a']++;
        for (char c : t.toCharArray()) freq[c - 'a']--;
        // Count chars that s has TOO MANY of (positive values)
        // Those need to be replaced — each excess = one replacement
        int steps = 0;
        for (int f : freq) if (f > 0) steps += f;
        return steps;
        // Why not count negatives? Every excess in s matches a deficit in t
        // Sum of positives = sum of |negatives| (both strings same length)
    }
    public static void main(String[] args) {
        System.out.println(minSteps("bab", "aab"));           // 1
        System.out.println(minSteps("leetcode", "practice")); // 5
        System.out.println(minSteps("anagram", "mangaar"));   // 0
        System.out.println("O(n) time, O(1) space");
        System.out.println("Steps = chars s has too many of → replace each one");
    }
}

