import java.util.*;
public class TopKFrequentWords {
    public static List<String> topKFrequent(String[] words, int k) {
        // Count frequencies:
        Map<String, Integer> freq = new HashMap<>();
        for (String w : words) freq.merge(w, 1, Integer::sum);
        // Min-heap: keep top k (by freq desc, lex asc for ties)
        PriorityQueue<String> pq = new PriorityQueue<>(
            (a, b) -> freq.get(a).equals(freq.get(b))
                ? b.compareTo(a)  // same freq: lex ascending (reverse for min-heap)
                : freq.get(a) - freq.get(b) // lower freq at top (min-heap)
        );
        for (String w : freq.keySet()) {
            pq.offer(w);
            if (pq.size() > k) pq.poll(); // evict worst
        }
        // Build result (min-heap has smallest at top, reverse for final list):
        LinkedList<String> result = new LinkedList<>();
        while (!pq.isEmpty()) result.addFirst(pq.poll());
        return result;
    }
    public static void main(String[] args) {
        System.out.println(topKFrequent(new String[]{"i","love","leetcode","i","love","coding"}, 2));
        System.out.println(topKFrequent(new String[]{"the","day","is","sunny","the","the","the","sunny","is","is"}, 4));
        System.out.println("O(n log k) — HashMap + min-heap of size k");
    }
}

