import java.util.*;
public class LongestKDistinct {
    public static int lengthOfLongestSubstringKDistinct(String s, int k) {
        if (k == 0) return 0;
        Map<Character, Integer> freq = new HashMap<>();
        int lo = 0, maxLen = 0;
        for (int hi = 0; hi < s.length(); hi++) {
            char c = s.charAt(hi);
            freq.put(c, freq.getOrDefault(c, 0) + 1);
            while (freq.size() > k) {           // too many distinct
                char left = s.charAt(lo);
                freq.put(left, freq.get(left) - 1);
                if (freq.get(left) == 0) freq.remove(left);
                lo++;
            }
            maxLen = Math.max(maxLen, hi - lo + 1);
        }
        return maxLen;
    }
    public static void main(String[] args) {
        System.out.println(lengthOfLongestSubstringKDistinct("eceba", 2));  // 3
        System.out.println(lengthOfLongestSubstringKDistinct("aa", 1));     // 2
        System.out.println(lengthOfLongestSubstringKDistinct("aabbcc", 2)); // 4
        System.out.println("O(n) — variable sliding window with HashMap");
    }
}

