public class GoodSubstrings {
    public static int countGoodSubstrings(String s) {
        int count = 0;
        int[] freq = new int[26];
        // Build first window:
        for (int i = 0; i < Math.min(3, s.length()); i++)
            freq[s.charAt(i) - 'a']++;
        if (s.length() >= 3 && isAllDistinct(freq)) count++;
        // Slide:
        for (int i = 3; i < s.length(); i++) {
            freq[s.charAt(i) - 'a']++;       // add right
            freq[s.charAt(i - 3) - 'a']--;  // remove left
            if (isAllDistinct(freq)) count++;
        }
        return count;
    }
    static boolean isAllDistinct(int[] freq) {
        for (int f : freq) if (f > 1) return false;
        return true;
    }
    // Simpler O(n) approach: just check 3 chars directly
    public static int countGoodSubstringsSimple(String s) {
        int count = 0;
        for (int i = 0; i + 2 < s.length(); i++) {
            char a=s.charAt(i), b=s.charAt(i+1), c=s.charAt(i+2);
            if (a!=b && b!=c && a!=c) count++;
        }
        return count;
    }
    public static void main(String[] args) {
        System.out.println(countGoodSubstrings("xyzzaz"));    // 1
        System.out.println(countGoodSubstrings("aababcabc")); // 4
        System.out.println(countGoodSubstringsSimple("xyzzaz")); // 1 — simpler
        System.out.println("O(n) — fixed window k=3");
    }
}

