import java.util.*;
public class FrequencySynthesis {
    static boolean isAnagram(String s, String t) {
        if(s.length()!=t.length()) return false;
        int[] f=new int[26];
        for(char c:s.toCharArray()) f[c-'a']++;
        for(char c:t.toCharArray()) if(--f[c-'a']<0) return false;
        return true;
    }
    static List<List<String>> groupAnagrams(String[] strs) {
        Map<String,List<String>> m=new HashMap<>();
        for(String s:strs){char[] c=s.toCharArray();Arrays.sort(c);m.computeIfAbsent(new String(c),k->new ArrayList<>()).add(s);}
        return new ArrayList<>(m.values());
    }
    static List<Integer> findAllAnagrams(String s, String p) {
        List<Integer> res=new ArrayList<>();
        if(s.length()<p.length()) return res;
        int[] need=new int[26],have=new int[26],k=new int[]{p.length()};
        for(char c:p.toCharArray()) need[c-'a']++;
        for(int i=0;i<k[0];i++) have[s.charAt(i)-'a']++;
        if(Arrays.equals(need,have)) res.add(0);
        for(int i=k[0];i<s.length();i++){have[s.charAt(i)-'a']++;have[s.charAt(i-k[0])-'a']--;if(Arrays.equals(need,have)) res.add(i-k[0]+1);}
        return res;
    }
    static String minWindow(String s, String t) {
        if(s.isEmpty()||t.isEmpty()) return "";
        int[] need=new int[128],w=new int[128];
        for(char c:t.toCharArray()) need[c]++;
        int req=t.length(),lo=0,minL=Integer.MAX_VALUE,ms=0;
        for(int hi=0;hi<s.length();hi++){char c=s.charAt(hi);w[c]++;if(need[c]>0&&w[c]<=need[c])req--;while(req==0){if(hi-lo+1<minL){minL=hi-lo+1;ms=lo;}char l=s.charAt(lo);w[l]--;if(need[l]>0&&w[l]<need[l])req++;lo++;}}
        return minL==Integer.MAX_VALUE?"":s.substring(ms,ms+minL);
    }
    public static void main(String[] args) {
        System.out.println("1. isAnagram('anagram','nagaram')="+isAnagram("anagram","nagaram"));
        System.out.println("2. groupAnagrams=['eat','tea','tan','ate']="+groupAnagrams(new String[]{"eat","tea","tan","ate"}));
        System.out.println("3. findAllAnagrams('cbaebabacd','abc')="+findAllAnagrams("cbaebabacd","abc"));
        System.out.println("4. minWindow('ADOBECODEBANC','ABC')="+minWindow("ADOBECODEBANC","ABC"));
        boolean allPass=isAnagram("anagram","nagaram")
            &&groupAnagrams(new String[]{"eat","tea","tan","ate"}).size()==2
            &&findAllAnagrams("cbaebabacd","abc").equals(Arrays.asList(0,6))
            &&minWindow("ADOBECODEBANC","ABC").equals("BANC");
        System.out.println("All pass: "+allPass);
    }
}
